import { createContext, useContext, useEffect, useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { createHash } from 'crypto';

interface NonceContextType {
  nonce: string;
  refreshNonce: () => void;
}

const NonceContext = createContext<NonceContextType | null>(null);

// Secure nonce generation
function generateSecureNonce(): string {
  if (typeof window === 'undefined') {
    // Server-side generation
    return createHash('sha256')
      .update(uuidv4() + Date.now().toString())
      .digest('base64');
  } else {
    // Client-side generation
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return btoa(String.fromCharCode.apply(null, Array.from(array)));
  }
}

// Nonce validation
function isValidNonce(nonce: string): boolean {
  // Minimum length requirement
  if (nonce.length < 32) return false;

  // Check for allowed characters (base64)
  const base64Regex = /^[A-Za-z0-9+/=]+$/;
  if (!base64Regex.test(nonce)) return false;

  return true;
}

interface NonceProviderProps {
  children: React.ReactNode;
  initialNonce?: string;
}

export function NonceProvider({ children, initialNonce }: NonceProviderProps) {
  const [nonce, setNonce] = useState<string>(() => {
    if (initialNonce && isValidNonce(initialNonce)) {
      return initialNonce;
    }
    return generateSecureNonce();
  });

  const refreshNonce = () => {
    setNonce(generateSecureNonce());
  };

  // Automatically refresh nonce periodically
  useEffect(() => {
    const interval = setInterval(refreshNonce, 1800000); // 30 minutes
    return () => clearInterval(interval);
  }, []);

  // Refresh nonce when tab becomes visible
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        refreshNonce();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, []);

  return (
    <NonceContext.Provider value={{ nonce, refreshNonce }}>
      {children}
    </NonceContext.Provider>
  );
}

export function useNonce() {
  const context = useContext(NonceContext);
  if (!context) {
    throw new Error('useNonce must be used within a NonceProvider');
  }
  return context.nonce;
}

