import { createHash, randomBytes } from 'crypto';

export class NonceService {
  private nonceStore: Map<string, { nonce: string; timestamp: number }> = new Map();
  private readonly NONCE_TIMEOUT = 1800000; // 30 minutes

  generateNonce(): string {
    const nonce = createHash('sha256')
      .update(randomBytes(32))
      .digest('base64');

    this.nonceStore.set(nonce, {
      nonce,
      timestamp: Date.now(),
    });

    // Clean up expired nonces
    this.cleanupExpiredNonces();

    return nonce;
  }

  validateNonce(nonce: string): boolean {
    const storedNonce = this.nonceStore.get(nonce);

    if (!storedNonce) return false;

    const isExpired = Date.now() - storedNonce.timestamp > this.NONCE_TIMEOUT;

    if (isExpired) {
      this.nonceStore.delete(nonce);
      return false;
    }

    return true;
  }

  private cleanupExpiredNonces(): void {
    const now = Date.now();
    for (const [key, value] of this.nonceStore.entries()) {
      if (now - value.timestamp > this.NONCE_TIMEOUT) {
        this.nonceStore.delete(key);
      }
    }
  }
}

